const inputText = $json.input || "";
const latest = $json || null;

// Try to extract timestamp from your sheet row
const ts = latest?.Timestamp || latest?.timestamp || null;

function toDate(val) {
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

let status = {
  ok: false,
  stale: true,
  lastTimestamp: ts,
  reason: "No station data returned"
};

if (ts) {
  const dt = toDate(ts);
  if (dt) {
    const now = new Date();
    const diffMin = (now.getTime() - dt.getTime()) / 60000;
    status.ok = diffMin <= 90;
    status.stale = diffMin > 90;
    status.reason = status.ok ? "Station fresh" : `Station stale (${Math.round(diffMin)} min old)`;
  } else {
    status.reason = "Could not parse station timestamp";
  }
}

return [{
  json: {
    input: inputText,
    station_status: status
  }
}];

function safeItems(nodeName) {
  try { return $items(nodeName) ?? []; } catch (e) { return []; }
}

// Router plan (already normalized into top-level keys)
const router = safeItems("Normalize Router Plan")[0]?.json ?? {
  need_forecast: false,
  forecast_selector: "none",
  offset_days: 0,
  start_offset: 0,
  end_offset: 0,
};

// Forecast rows from Google Sheets (Forecast_10Day_Current)
const inputRows = $input.all().map(i => i.json);

// --- Helpers ---
function parseDateYYYYMMDD(s) {
  if (!s) return null;
  const str = String(s).trim();
  // Expecting "YYYY-MM-DD"
  const d = new Date(str + "T00:00:00");
  return isNaN(d.getTime()) ? null : d;
}

function toYYYYMMDD(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

function addDays(d, n) {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  x.setHours(0,0,0,0);
  return x;
}

function nextSaturday(from) {
  const d = new Date(from);
  d.setHours(0,0,0,0);
  const dow = d.getDay(); // 0 Sun .. 6 Sat
  const add = (6 - dow + 7) % 7 || 7; // if already Sat, take next Sat
  return addDays(d, add);
}

// Normalize forecast rows using YOUR sheet headers
const forecastRows = inputRows
  .map(r => {
    const dateStr =
      r.forecast_date ?? r.ForecastDate ?? r.forecastDate ??
      r.date ?? r.Date ?? r.day ?? r.time;

    const d = parseDateYYYYMMDD(dateStr);

    return {
      ...r,
      _dateStr: dateStr,
      _date: d,
      _offset: Number(r.offset_days ?? r.offsetDays ?? r.OffsetDays ?? 0),
    };
  })
  .filter(r => r._date); // must have valid date

// Anchor "today" to first forecast row (more reliable than server timezone)
let today = new Date();
today.setHours(0,0,0,0);
if (forecastRows.length > 0) {
  const first = forecastRows.slice().sort((a,b) => a._date - b._date)[0];
  today = new Date(first._date);
  today.setHours(0,0,0,0);
}

const selector = String(router.forecast_selector || "none").toLowerCase();
let selected = [];

if (!router.need_forecast || selector === "none") {
  selected = [];

} else if (selector === "single") {
  const want = Number(router.offset_days ?? 0);
  selected = forecastRows.filter(r => r._offset === want);

} else if (selector === "range") {
  const s = Number(router.start_offset ?? 0);
  const e = Number(router.end_offset ?? 0);
  selected = forecastRows.filter(r => r._offset >= s && r._offset <= e);

} else if (selector === "weekend") {
  const sat = nextSaturday(today);
  const sun = addDays(sat, 1);
  const satStr = toYYYYMMDD(sat);
  const sunStr = toYYYYMMDD(sun);

  selected = forecastRows.filter(r => {
    const ds = toYYYYMMDD(r._date);
    return ds === satStr || ds === sunStr;
  });

} else if (selector === "weekdays_remaining" || selector === "this_week") {
  // Today -> Friday
  const start = new Date(today);
  const dow = start.getDay(); // 0 Sun .. 6 Sat
  const daysToFri = (5 - dow + 7) % 7; // Fri=5
  const end = addDays(start, daysToFri);

  selected = forecastRows.filter(r => r._date >= start && r._date <= end);

} else {
  // fallback: today only
  selected = forecastRows.filter(r => r._offset === 0);
}

// Sort chronologically
selected.sort((a,b) => a._date - b._date);

return [{
  json: {
    router_plan: router,
    forecast_selected: selected,
    debug: {
      selector,
      today_anchor: toYYYYMMDD(today),
      input_count: inputRows.length,
      parsed_count: forecastRows.length,
      selected_count: selected.length
    }
  }
}];

function safeFirst(nodeName) {
  try {
    const arr = $items(nodeName);
    return (arr && arr.length) ? arr[0].json : null;
  } catch (e) {
    return null;
  }
}

// Inputs coming from earlier nodes
const questionItem = safeFirst("When Executed by Another Workflow") || $json || {};
const question = questionItem.input || questionItem.question || "";

// Station status + latest row
const stationStatus = safeFirst("Precheck - Station Status")?.station_status
  ?? safeFirst("Precheck - Station Status")
  ?? null;

const latestStationRow = safeFirst("Precheck - Latest Station Row") ?? null;

// Daily pivot (optional)
const dailyPivotRows = safeFirst("Read Daily_Pivot")?.data
  ?? safeFirst("Read Daily_Pivot")   // if node returns array items instead of wrapped data
  ?? [];

// Forecast selection (IMPORTANT)
const forecastNode = safeFirst("Forecast Filter") ?? {};
const routerPlan = forecastNode.router_plan || safeFirst("Normalize Router Plan") || {};
const forecastSelected = forecastNode.forecast_selected || [];

// Current time
const nowIso = new Date().toISOString();

return [{
  json: {
    question,
    router_plan: routerPlan,
    station_status: stationStatus,
    latest_station_row: latestStationRow,
    daily_pivot_rows: Array.isArray(dailyPivotRows) ? dailyPivotRows : [],
    forecast_selected: Array.isArray(forecastSelected) ? forecastSelected : [],
    now_iso: nowIso,
  }
}];

// Router node returns a wrapper like:
// { output: [ { content: [ { text: { ...plan } } ] } ] }

const raw = $json;

// Try to extract the plan object safely
const plan =
  raw?.output?.[0]?.content?.[0]?.text ??
  raw?.output?.[0]?.content?.[0]?.text?.text ?? // (some node variants nest)
  null;

if (!plan || typeof plan !== "object") {
  return [{
    json: {
      need_station: true,
      need_daily_pivot: false,
      need_forecast: true,
      forecast_selector: "range",
      offset_days: 0,
      start_offset: 0,
      end_offset: 3,
      analysis: "none",
      wind_threshold_kmh: null,
      include_links: false,
      _router_error: "Router output could not be parsed"
    }
  }];
}

return [{ json: plan }];

